import { useEffect, useState, useMemo } from 'react';
import { useSearchParams } from 'react-router-dom';
import { transformToFinancialProduct, applyFilters, DEFAULT_FILTERS } from '../utils/finance';
import ProductCard from '../components/ProductCard';
import FilterPanel from '../components/FilterPanel';
import './ProductListing.css';

export default function ProductListing() {
  const [products, setProducts]   = useState([]);
  const [loading, setLoading]     = useState(true);
  const [error, setError]         = useState(null);
  const [filters, setFilters]     = useState(DEFAULT_FILTERS);
  const [searchParams]            = useSearchParams();

  // Read ?category= from URL (from home page category nav)
  useEffect(() => {
    const cat = searchParams.get('category');
    if (cat) {
      setFilters(prev => ({ ...prev, categories: [cat] }));
    }
  }, [searchParams]);

  useEffect(() => {
    setLoading(true);
    fetch('https://fakestoreapi.com/products')
      .then(r => { if (!r.ok) throw new Error('API error'); return r.json(); })
      .then(data => {
        setProducts(data.map(transformToFinancialProduct));
        setLoading(false);
      })
      .catch(err => {
        setError('Failed to load products. Please try again.');
        setLoading(false);
      });
  }, []);

  // Apply all filters with AND logic
  const filtered = useMemo(() => applyFilters(products, filters), [products, filters]);

  return (
    <div className="page page-enter">
      <div className="container">
        <div className="pl-header">
          <div>
            <h1 className="section-title">All <span>Products</span></h1>
            <p className="section-subtitle">Browse and filter {products.length} financial instruments</p>
          </div>
        </div>

        <div className="pl-layout">
          <FilterPanel
            filters={filters}
            onFilterChange={setFilters}
            productCount={filtered.length}
            totalCount={products.length}
          />

          <div className="pl-content">
            {loading && (
              <div className="loading-wrap"><div className="spinner" /><p>Loading products…</p></div>
            )}
            {error && (
              <div className="error-state">
                <p>⚠️ {error}</p>
                <button className="btn btn-outline" onClick={() => window.location.reload()}>Retry</button>
              </div>
            )}
            {!loading && !error && filtered.length === 0 && (
              <div className="empty-state">
                <h3>No products match your filters</h3>
                <p>Try adjusting or resetting the filters.</p>
              </div>
            )}
            {!loading && !error && filtered.length > 0 && (
              <>
                <p className="pl-result-count">
                  Showing <strong>{filtered.length}</strong> of {products.length} products
                </p>
                <div className="products-grid">
                  {filtered.map(p => (
                    <ProductCard key={p.id} product={p} />
                  ))}
                </div>
              </>
            )}
          </div>
        </div>
      </div>
    </div>
  );
}
